import { _decorator, Component, log, input, Input, EventKeyboard, KeyCode } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { BaseSpine } from '../Spine/BaseSpine';
import { MULTIPLIER_EVENT } from '../Multiplier/MultiplierManager';
import { REEL_UI_EVENT } from '../ReelUIManager';
import { Define } from 'db://astarte-framework/utilis';
import { AudioManager } from '../Audio/AudioManager';
import { BLACK_MASK_EVENT } from '../BlackMaskManager';
import { DEBUG } from 'cc/env';
const { ccclass, property } = _decorator;

export enum PreWinType
{
    Scatter,
    Collect,
}

export const PRE_WIN_EVENT = {
    /**
     * @ch 播放PreWin動畫
     * @param preWinType PreWin類型
     * @param callback 完成後回調
     */
    PLAY_PRE_WIN_ANIM: "PRE_WIN_PLAY_PRE_WIN_ANIM",
} as const;

@ccclass('PreWinManager')
export class PreWinManager extends Component {

    //#region 屬性
    @property( {
        type: BaseSpine,
        tooltip: "PreWin Spine"
    } )
    private m_preWinSpine: BaseSpine = null;

    //#endregion 屬性

    //#region 變數
    /**@ch 各種類型對應的動畫名稱*/
    private m_animationNames: Record<PreWinType, string> = {
        [PreWinType.Scatter]: "LV1",
        [PreWinType.Collect]: "LV2",
    }

    /**@ch 是否註冊事件*/
    private m_isEventRegistered: boolean = false;

    /**@ch 事件列表*/
    private readonly EVENT_LIST: string[] = [
        PRE_WIN_EVENT.PLAY_PRE_WIN_ANIM,
    ];

    /**@ch 聽牌框延遲時間*/
    private readonly PREWIN_FRAME_DELAYS: number[] = [1.7, 3.7];

    /**@ch Collect PreWin 音效延遲時間*/
    private readonly COLLECT_PREWIN_SOUND_DELAY: number = 2.6;
    //#endregion 變數

    //#region Lifecycle Methods
    onLoad() {
        this.ValidateProperties();
        this.RegisterEvent();
    }

    onDestroy() {
        this.UnregisterEvent();
    }
    //#endregion Lifecycle Methods

    //#region Initialization Methods
    /**
     * @ch 驗證必要屬性
     */
    private ValidateProperties() {
        if (!this.m_preWinSpine) {
            log('[PreWinManager] PreWin Spine 未設定，部分功能可能無法正常運作');
        }
    }
    //#endregion Initialization Methods

    //#region Event Methods
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) return;

        this.EVENT_LIST.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.RegisterTestKeyCodes();

        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件

import { _decorator, Component, error, TextAsset, warn, Enum, input, Input, EventKeyboard, log, KeyCode } from 'cc';
import Game_Define, { SymbolInfo, FeverGameType } from './Game_Define';
import { eventManager, newBottombarManager } from 'db://astarte-framework/Managers';
import { DEBUG } from 'cc/env';
import { tools } from 'db://astarte-framework/utilis';
const { ccclass, property } = _decorator;

/**@ch 假轉輪帶讀取模式 */
enum FakeReelReadMode {
    /**@ch 以列讀取（橫向，檔案每一行 = 一條假轉輪帶）*/
    Row = 0,

    /**@ch 以行讀取（縱向，檔案每一列 = 一條假轉輪帶）*/
    Column = 1
}

/**@ch 假轉輪帶投注模式 */
export enum FakeReelBetMode {
    /**@ch 一般投注 */
    Normal   = 0,
    /**@ch 道具卡 */
    ToolCard = 1,
    /**@ch 購買 Bonus */
    BuyBonus = 2,
    /**@ch 加注 Extra Bet */
    ExtraBet = 3,
}

/**@ch 假轉輪管理器事件 */
export const FAKE_REEL_MANAGER_EVENT = {
    /**
     * @ch 載入假轉輪帶資料
     */
    LOAD_FAKE_REEL_DATA: "FAKE_REEL_LOAD_DATA",

    /**
     * @ch 生成假轉輪帶 Seed
     * @param betMode 投注模式（FakeReelBetMode，預設 Normal）
     * @param fakeReelWeightResult Server 回傳的假轉輪帶檔案索引（IRoundInfo.FakeReelWeightResult）
     * @param callback 回呼函式 (result: FakeReelSeed | null) => void
     */
    GENERATE_FAKE_REEL_SEED: "FAKE_REEL_GENERATE_SEED",

    /**
     * @ch 根據 Seed 取得假轉輪帶資料
     * @param seed FakeReelSeed
     * @param reelIndex Reel 編號
     * @param count 要取得的符號數量
     * @param autoUpdatePosition 是否自動更新位置（預設 false）
     * @param isDownward 是否往下取值（預設 true，true=位置+1，false=位置-1）
     * @param callback 回呼函式 (result: number[] | null) => void
     */
    GET_FAKE_REEL_DATA_BY_SEED: "FAKE_REEL_GET_DATA_BY_SEED",

    /**
     * @ch 為 Coin Symbol (id=14) 生成金額
     * @param betMode 投注模式（FakeReelBetMode，預設 Normal）
     * @param callback 回呼函式 (result: { credit: number, symbolId: number } | null) => void
     */
    GENERATE_COIN_CREDIT: "FAKE_REEL_GENERATE_COIN_CREDIT",

    /**
     * @ch 根據 Seed 取得假轉輪帶符號資料
     * @param seed FakeReelSeed
     * @param reelIndex Reel 編號
     * @param count 要取得的符號數量
     * @param autoUpdatePosition 是否自動更新位置（預設 false）
     * @param isDownward 是否往下取值（預設 true，true=位置+1，false=位置-1）
     * @param callback 回呼函式 (result: SymbolInfo[] | null) => void
     */
    GET_FAKE_REEL_SYMBOL_BY_SEED: "FAKE_REEL_GET_SYMBOL_BY_SEED",

    /**
     * @ch 處理 Seed 位置 (正數=加，負數=減)
     * @param seed FakeReelSeed
     * @param reelIndex Reel 編號
     * @param count 要加減的符號數量 (正數=加，負數=減)
     * @param callback 回呼函式 (result: FakeReelSeed | null) => void
     */
    PROCESS_SEED_POSITION: "FAKE_REEL_PROCESS_SEED_POSITION",
};

export class FakeReelData {
    /**@ch 假轉輪帶資料 [假轉輪帶編號] = 符號陣列 */
    public ReelData: { [index: number]: number[] } = {};
}

/**@ch Coin 金額權重表項目 */
export class CoinCreditWeightEntry {
    /**@ch 金額（數字，以幣為單位，例如 5000 = 50.00 元）或 'JP' 標記 */
    public credit: number | 'JP' = 0;

    /**@ch 權重值 */
    public weight: number = 0;
}

/**@ch Coin 金額權重表 */
export class CoinCreditWeightTable {
    /**@ch 權重表項目列表 */
    public entries: CoinCreditWeightEntry[] = [];

