import { _decorator, Component, Label, Sprite, SpriteFrame, tween, Tween, v3 } from 'cc';
import { Common } from '../Common/Common';
const { ccclass, property } = _decorator;

/**
 * @ch 外部控制顯示 Jackpot 圖片或數字文字
 * - Jackpot（1:Mini, 2:Minor, 3:Major, 4:Mega, 5:Grand）→ 顯示對應圖片
 * - 數字 → 顯示 Label 值
 */
@ccclass( 'ShowRewardController' )
export class ShowRewardController extends Component
{
    @property( {
        type: [SpriteFrame],
        tooltip: "Jackpot 圖片陣列 [0:Mini, 1:Minor, 2:Major, 3:Mega, 4:Grand]"
    } )
    private m_jackpotSpriteFrames: SpriteFrame[] = [];

    @property( {
        type: Sprite,
        tooltip: "顯示 Jackpot 圖片的 Sprite"
    } )
    private m_rewardSprite: Sprite = null;

    @property( {
        type: Label,
        tooltip: "顯示數字的 Label"
    } )
    private m_rewardLabel: Label = null;

    /**
     * @ch 記住上一次 ShowReward 的型態（圖 or 字）。
     *     Show() 會依這個狀態只啟用其中一個節點，避免圖字同時出現。
     * - null：尚未設定過，Show() 會保持兩者關閉
     * - true：上次顯示 Jackpot 圖
     * - false：上次顯示數字 Label
     */
    private m_lastIsJackpot: boolean | null = null;

    /**
     * @ch 顯示獎勵：可以是 Jackpot（圖片）或數字（文字）
     * @param isJackpot true=用 jpIndex 顯示圖片；false=用 value 顯示數字
     * @param value 當 isJackpot=true 時為 jpIndex（0:Mini~4:Grand）；否則為數值
     */
    public ShowReward( isJackpot: boolean, value: number ): void
    {
        this.m_lastIsJackpot = isJackpot;

        const spriteNode = this.m_rewardSprite?.node;
        const labelNode = this.m_rewardLabel?.node;

        // 重要：避免 UpdateRewardWithTween 把 scale tween 到 0 後，
        // 下一次同一 round 再顯示 JP / 數字時節點仍然縮到 0 而「看起來消失」
        if ( spriteNode )
        {
            Tween.stopAllByTarget( spriteNode );
            spriteNode.setScale( v3( 1, 1, 1 ) );
        }
        if ( labelNode )
        {
            Tween.stopAllByTarget( labelNode );
            labelNode.setScale( v3( 1, 1, 1 ) );
        }

        if ( isJackpot )
        {
            const jpIndex = value - 1; // 外部 1:Mini~5:Grand，這裡轉成 0-based

            // 關閉文字
            if ( labelNode )
            {
                labelNode.active = false;
            }

            // 顯示圖片
            if ( !this.m_rewardSprite || !spriteNode )
            {
                return;
            }
            if ( jpIndex >= 0 && jpIndex < this.m_jackpotSpriteFrames.length && this.m_jackpotSpriteFrames[ jpIndex ] )
            {
                this.m_rewardSprite.spriteFrame = this.m_jackpotSpriteFrames[ jpIndex ];
                spriteNode.active = true;
            }
            else
            {
                spriteNode.active = false;
            }
        }
        else
        {
            // 關閉圖片
            if ( spriteNode )
            {
                spriteNode.active = false;
            }

            // 顯示文字
            if ( !this.m_rewardLabel )
            {

