import { Common } from '../Common/Common';
import { AudioManager } from '../Audio/AudioManager';
const { ccclass, property } = _decorator;

export const EXTRA_BET_EFFECT_MANAGER_EVENT = {
    /**
     * @ch 播放激活效果
     * @param (選填) callback 完成後回調
     */
    PLAY_ACTIVATE_EFFECT: "EXTRA_BET_EFFECT_MANAGER_PLAY_ACTIVATE_EFFECT",
}

@ccclass('ExtraBetEffectManager')
export class ExtraBetEffectManager extends Component {

    //#region Constants
    /**@ch 需要註冊的事件列表*/
    private static readonly EVENTS_TO_REGISTER = [
        EXTRA_BET_EFFECT_MANAGER_EVENT.PLAY_ACTIVATE_EFFECT,
    ];
    //#endregion Constants

    //#region Properties
    /**@ch 激活效果 Spine*/
    @property( {
        type: BaseSpine,
        displayName: "激活效果 Spine"
    } )
    m_activateEffectSpine: BaseSpine = null;
    //#endregion Properties

    //#region Variables
    private readonly ANIMATION_KEY_NAME_CONFIG = {
        Activate: 'In',
    } as const;

    /**@ch 是否已註冊事件*/
    private m_isEventRegistered: boolean = false;

    private m_gameView: GameView = null;
    //#endregion Variables

    //#region Lifecycle
    onLoad() {
        this.RegisterEvent();
        if (!this.m_gameView) {
            this.m_gameView = Common.GetGameView();
        }
    }

    onDestroy() {
        this.UnregisterEvent();
    }
    //#endregion Lifecycle

    //#region Methods
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) {
            return;
        }

        ExtraBetEffectManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件
     */

