}

/**@ch 按下開始按鍵 */
ClickSpin() {
    AudioManager.Play(AudioManager.AudioClips.Spin);

    //按下開始按鍵
    if (stateManager.Current() !== CommonState.IDLE || newExtraManager.IsNowInDemoMenu) {
        return;
    }

    const isExtraOn = this.m_extraBetComp?.IsExtra ?? false;
    const isFreePlay = newBottombarManager.IsFreeSpin || this.IsFreeGame;
    const hasEnoughForExtraBet = !isExtraOn || isFreePlay ||
        tools.strip(newBottombarManager.GetChips()) >= tools.strip(newBottombarManager.GetRealBetValue());

    if (
        (
            (this.m_buyBonus && tools.strip(newBottombarManager.GetChips()) >= this.m_buyBonus?.GetBuyBonusBet())
            || !this.m_buyBonus
            || newBottombarManager.IsFreeSpin
            || this.IsFreeGame
        )
        && hasEnoughForExtraBet
        && backpackManager.IsBackpackPass()
        && !giftCodeManager.IsOpen()
    ) {
        newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        this.m_buyBonus?.Hide();
        this.m_extraBetComp?.OnSpin();
        eventManager.Dispatch(CommonEventName.SpinReqNotify);
        if (!newBottombarManager.IsFreeSpin && !this.IsFreeGame)
            this.UpdateFakeReelBetMode();
    }
    else {
        this.m_buyBonus?.CleanInfo();
        if (backpackManager.IsBackpackPass() && !giftCodeManager.IsOpen()) {
            let betList = newBottombarManager.GetBetList();
            if (
                tools.strip(newBottombarManager.GetNowBetValue()) === tools.strip(betList[0])
                || newBottombarManager.GetChips() < tools.strip(betList[0])
            ) {
                msgBoxManager.ShowMessageBox(Define.StringKey.MSGBOX_MONEY_NOT_ENOUGH);
            }
            else {
                msgBoxManager.ShowMessageBox(Define.StringKey.MSGBOX_MONEY_NOT_ENOUGH_DOWN_BET);
            }
        }
        else {
            newBottombarManager.SetSpinState(SlotBottomBarState.IDLE);
            stateManager.NextState(CommonState.IDLE);
        }
    }
}
//#endregion iBuyBonusGameView

/**
 * @ch 玩家觸發Spin指令
 * @param fileIndexOverride 可選：透傳給 SlotReels.StartSpin 的假轉輪帶 fileIndex 覆寫值
 *                          （EnterFreeState 等需指定下一輪 fileIndex 的場景使用）
 * @param continueSpin 可選：true 時 SlotReels.StartSpin 保留時間軸/位置軸狀態（用於 EnterFreeState
 *                     表演結束直接接 FG 第一手的連續轉動場景，避免時間軸與 ColumnSymbol 視覺位置不同步）
 */
StartSpin(fileIndexOverride?: number, continueSpin: boolean = false)
{
    this.m_isHardStop = newBottombarManager.IsHardStop;

    // 清理上次可能保留的 Collect spine（有對獎演出的 spine）
    // 無論是 FreeGame 還是 NormalGame，都要在下次 spin 時清理
    this.m_effectPlate.ReturnNormalLayer();

    this.m_slotReels.StartSpin(fileIndexOverride, continueSpin);

    // Respin 中已鎖定在盤面的符號不重複播放 In 動畫
    if ( this.IsRespinGame )
    {
        this.m_slotReels.SuppressInAnimationForRespinLockedPos();
    }

    // FreeGame 和 RespinGame 狀態下都不歸零贏分（需要累積顯示）
    // 只有一般遊戲狀態下才歸零
    if ( !this.IsFreeGame && !this.IsRespinGame )
    {
        newBottombarManager.SetWinValue( 0 );
    }
}

