import { _decorator, Component, Node, Vec3 } from 'cc';
import { BaseSpine } from './Spine/BaseSpine';
const { ccclass, property } = _decorator;

@ccclass('FlyToCollectController')
export class FlyToCollectController extends Component {
    @property(Node)
    private m_longNode: Node = null;

    @property(Node)
    private m_shortNode: Node = null;

    @property(BaseSpine)
    private m_collectSpine: BaseSpine = null;

    @property(Node)
    private m_collectNode: Node = null;

    /**
     * @ch 設定要使用的目標節點（Long / Short）
     * @param isLong 是否使用長版節點
     * @returns 目標節點（用來掛 cashNode）
     */
    public SetTargetNode( isLong: boolean ): Node
    {
        return ( isLong ? this.m_longNode : this.m_shortNode ) || this.node;
    }

    /**
     * @ch 由外部帶入最終定點位置，設定到 Collect 節點後播放 Trigger 動畫
     * @param finalPosition 世界座標最終位置
     */
    public async PlayCollectAnimation( finalPosition: Vec3 ): Promise<void>
    {
        if ( !this.m_collectSpine )
        {
            return;
        }
        if ( this.m_collectNode )
        {
            this.m_collectNode.setWorldPosition( finalPosition );
        }
        await this.m_collectSpine.PlayAnimation( "Trigger", this.m_collectSpine.Spine, false );
    }
}

