    /**@ch
     * 播放收集 Cash 到 Collect 的動畫
     * @param (必填) cashNode 收集 Cash 的節點
     * @param (必填) startWorldPosition 起始位置
     * @param (必填) endWorldPosition 結束位置
     * @param (選填) callback 完成後回調
     */
    PLAY_FLY_TO_COLLECT_ANIMATION: "FLY_PLAY_FLY_TO_COLLECT_ANIMATION",

    /**@ch
     * 播放投入 Cash 的 Spine 演出
     * @param (必填) countPerRound 每列投入的 spine 數量
     * @param (必填) 要投入哪幾列
     * @param (選填) intervalSeconds 間隔幾秒
     * @param (選填) callback 完成後回調
     */
    PLAY_ADD_CASH_ANIMATION: "FLY_PLAY_ADD_CASH_ANIMATION",

