    @property( {
        type: Node,
        tooltip: "收集 Cash 到 Collect 的節點"
    } )
    m_collectNodePrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "投入 Cash 的 Spine Prefab（可同時播放多個）"
    } )
    m_addCashSpinePrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "Scatter to MagicPot 的 Prefab"
    } )
    m_scatterToMagicPotPrefab: Prefab = null;

    @property({
        type: [Node],
        tooltip: "投入的位子"
    })
    m_addCashPositions: Node[] = [];

    @property({
        type: [Node],
        tooltip: "投入後要移動到的位子"
    })
    m_addCashTargetPositions: Node[] = [];

    @property({
        type: [Node],
        tooltip: "遮罩父節點"
    })
