import { Node } from "cc";
import { Astarte } from "../global";

interface ExtraBetController
{
    /**
     * 設定由公版控制ExtraBet,基本為強制啟動型,因此不需要有表演相關流程
     * 僅須設定"相關旗標"與"EX BET按鈕和場景變化"即可
     * @param node ExtraBet節點本體 (隱藏節點用)
     * @param changeStateCb 由機制強制開關ExtraBet的Callback (利用傳入參數isActive決定ExtraBet狀態)
     */
    Init( node: Node, changeStateCb: ( isActive: boolean ) => Promise<void> ): void;

    /**
     * 設定ExtraBet節點是否顯示.強制性的,關閉後只能再以此方法開啟
     */
    SetExtraBetNodeVisible( isVisible: boolean ): void

    /**
     * 強制切換ExtraBet模式
     * @param isActive 是否啟動ExtraBet
     * @param needInvisible 是否需要隱藏節點 (預設false,只再isActive為false時有效)
     */
    ForceChangeExtraBetMode( isActive: boolean, needInvisible?: boolean ): void

    get PerformanceEnd(): boolean;
}

let node: ExtraBetController;
export function UpdateExtraBetController()
{
    node = Astarte.ExtraBetController;
}
export { node as extraBetController };

