575	     * @ch 將 server 端等級（0~6）映射為 client 端顯示等級（0~3）
576	     * 對照：0,1→0｜2,3→1｜4,5→2｜6→3
577	     * ⚠️ 非冪等：對 client 值再呼叫會得到 0,0,1,1，僅允許在 server 值進入時呼叫
578	     * @param serverLevel server 端能量等級
579	     * @returns client 端顯示等級（0~BINGO_LEVEL）
580	     */
581	    private static ConvertServerLevelToClient(serverLevel: number): number {
582	        if (serverLevel >= 6) return MagicPotController.BINGO_LEVEL;
583	        return Math.max(0, Math.floor(serverLevel / 2));
584	    }
585	
586	    /**
587	     * @ch 設置等級（對外事件入口）
588	     * ⚠️ 契約：`level` 為 server 端等級（0~6），內部會映射為 client 等級。
589	     * 內部呼叫（已知值為 client level）請使用 `SetClientLevelInternal`，避免二次轉換。
590	     * @param level server 端等級
591	     * @param isPlayAnimation 是否播放動畫
592	     */
593	    SetLevel(level: number, isPlayAnimation: boolean = true) {
594	        this.m_serverLevel = level;
595	        const clientLevel = MagicPotController.ConvertServerLevelToClient(level);
596	        this.SetClientLevelInternal(clientLevel, isPlayAnimation);
597	    }
598	
599	    /**
600	     * @ch 設置 client 等級（內部使用，跳過 server→client 映射）
601	     * ⚠️ 警告：傳入必須是已映射的 client level（0~BINGO_LEVEL=3），內部不再做轉換
602	     * @param clientLevel client 端顯示等級
603	     * @param isPlayAnimation 是否播放動畫
604	     */
605	    private SetClientLevelInternal(clientLevel: number, isPlayAnimation: boolean = true) {
606	        this.m_level = clientLevel;
607	
608	        if (isPlayAnimation && this.m_gameView && !this.m_gameView.IsFreeGame) {
609	            this.PlayLevelAnimations(this.m_level);
610	        }
611	    }
612	
