 * @ch 將 server 端等級（0~6）映射為 client 端顯示等級（0~3）
 * 對照：0,1→0｜2,3→1｜4,5→2｜6→3
 * ⚠️ 非冪等：對 client 值再呼叫會得到 0,0,1,1，僅允許在 server 值進入時呼叫
 * @param serverLevel server 端能量等級
 * @returns client 端顯示等級（0~BINGO_LEVEL）
 */
private static ConvertServerLevelToClient(serverLevel: number): number {
    if (serverLevel >= 6) return MagicPotController.BINGO_LEVEL;
    return Math.max(0, Math.floor(serverLevel / 2));
}

/**
 * @ch 設置等級（對外事件入口）
 * ⚠️ 契約：`level` 為 server 端等級（0~6），內部會映射為 client 等級。
 * 內部呼叫（已知值為 client level）請使用 `SetClientLevelInternal`，避免二次轉換。
 * @param level server 端等級
 * @param isPlayAnimation 是否播放動畫
 */
SetLevel(level: number, isPlayAnimation: boolean = true) {
    this.m_serverLevel = level;
    const clientLevel = MagicPotController.ConvertServerLevelToClient(level);
    this.SetClientLevelInternal(clientLevel, isPlayAnimation);
}

/**
 * @ch 設置 client 等級（內部使用，跳過 server→client 映射）
 * ⚠️ 警告：傳入必須是已映射的 client level（0~BINGO_LEVEL=3），內部不再做轉換
 * @param clientLevel client 端顯示等級
 * @param isPlayAnimation 是否播放動畫
 */
private SetClientLevelInternal(clientLevel: number, isPlayAnimation: boolean = true) {
    this.m_level = clientLevel;

    if (isPlayAnimation && this.m_gameView && !this.m_gameView.IsFreeGame) {
        this.PlayLevelAnimations(this.m_level);
    }
}

/**
 * @ch 獲取等級
 * 對外回傳 server 端等級（0~6），維持與舊版相同契約，避免呼叫端誤把回傳值再餵回 SetLevel 觸發二次轉換。
 * 若需要 client 顯示等級（0~3）請直接讀取 `m_level`（private）。
 * @returns server 端等級
 */
GetLevel(): number {
    return this.m_serverLevel;
