import { _decorator } from "cc";
import protocol from "@igs-arcade-division-rd2/uk_658_eyestrike_proto/ar2esProto.js";
import { tools } from "db://astarte-framework/utilis";

const { ccclass } = _decorator;
@ccclass( "RecoverSpinAck" )
export class RecoverSpinAck
{
    private static _instance: RecoverSpinAck | null = null;

    constructor()
    {
        if ( RecoverSpinAck._instance )
        {
            throw new Error( "Error: Instantiation failed: Use RecoverSpinAck.getInstance() instead of new." );
        }
        RecoverSpinAck._instance = this;
    }

    public static getInstance(): RecoverSpinAck
    {
        if ( !this._instance )
        {
            this._instance = new RecoverSpinAck();
        }
        return this._instance;
    }

    /**@ch 收到protocol的資料，要做復原 */
    RecoverSpinAck( ack: protocol.ar2esProto.ISpinAck )
    {
        let ret = new protocol.ar2esProto.SpinAck();
        ret.RoundQueue = this.TraverseRoundQueue( ack.RoundQueue );
        ret.FreeTotalWin = ack.FreeTotalWin || 0; // 免費遊戲總贏分
        ret.TotalWin = ack.TotalWin || 0; // 總贏分
        ret.Bet = ack.Bet || 0;
        ret.MultiplierIndex = ack.MultiplierIndex || 0; // 加乘倍率的index
        ret.EnergyLevel = ack.EnergyLevel || 0; // 能量等級
        ret.EnergyPoint = ack.EnergyPoint || 0; // 能量點數
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param RoundQueue 原始資料
     * @returns 轉換後的資料
     */
    TraverseRoundQueue( RoundQueue: protocol.ar2esProto.IRoundInfo[] ) : protocol.ar2esProto.RoundInfo[]
    {
        let roundQueue: protocol.ar2esProto.RoundInfo[] = [];
        for ( let i = 0; i < RoundQueue.length; ++i )
        {
            let t = new protocol.ar2esProto.RoundInfo();
            let cur = RoundQueue[ i ];

            t.MainPlateSymbol = this.TraverseCColumns( cur.MainPlateSymbol );
            t.FreePlateSymbol = this.TraverseCColumns( cur.FreePlateSymbol );
            t.FreePlateSymbolLog = this.TraverseCColumns( cur.FreePlateSymbolLog );
            t.AwardDataVec = this.TraverseAwardDataVec( cur.AwardDataVec );
            t.AwardTypeFlag = cur.AwardTypeFlag || 0;
            t.RoundWin = cur.RoundWin || 0;
            t.ReelWeightResult = cur.ReelWeightResult || 0;
            t.MaxFlag = cur.MaxFlag || false;
            t.FeaturePosQueue = this.TraverseFeaturePosQueue( cur.FeaturePosQueue );
            t.CurrFeverGameType = cur.CurrFeverGameType || 0;
            t.NextFeverGameType = cur.NextFeverGameType || 0;
            t.FreeRemainRound = cur.FreeRemainRound || 0;
            t.FreeNowRound = cur.FreeNowRound || 0;
            t.FreeGameWheelIndex = cur.FreeGameWheelIndex || 0;
            t.FreeGameWheelNumberIndex = cur.FreeGameWheelNumberIndex || 0;
            t.FreeTotalRound = cur.FreeTotalRound || 0;
            t.MysteryEventKind = cur.MysteryEventKind || 0;
            t.NearMissKind = cur.NearMissKind || 0;
            t.NearMissStartCol = cur.NearMissStartCol || 0;
            t.PreMultiplierIndex = cur.PreMultiplierIndex || 0;
            t.MainMultiplierIndex = cur.MainMultiplierIndex || 0;
            t.FreeMultiplierIndex = cur.FreeMultiplierIndex || 0;
            t.MultiplierUpgrade = this.TraverseMultiplierUpgrades( cur.MultiplierUpgrade );
            t.PreEnergyLevel = cur.PreEnergyLevel || 0;
            t.EnergyLevel = cur.EnergyLevel || 0;

